import anthropic, statistics, json
from datetime import datetime, timezone
from collections import defaultdict

_client = anthropic.Anthropic()

class MRMMonitor:
    """Collect ongoing monitoring data for SR 11-7 KPI reporting."""

    def __init__(self, model_id: str, mrm_record_id: str):
        self.model_id = model_id
        self.mrm_record_id = mrm_record_id
        self._calls: list[dict] = []

    def call(self, messages: list, system: str = "") -> str:
        kwargs = dict(model=self.model_id, max_tokens=1024, messages=messages)
        if system:
            kwargs["system"] = system
        resp = _client.messages.create(**kwargs)
        self._calls.append({
            "ts": datetime.now(timezone.utc).isoformat(),
            "input_tokens": resp.usage.input_tokens,
            "output_tokens": resp.usage.output_tokens,
            "stop_reason": resp.stop_reason,
        })
        return resp.content[0].text

    def monthly_kpi_report(self) -> dict:
        if not self._calls:
            return {"mrm_record_id": self.mrm_record_id, "calls": 0}
        output_tokens = [c["output_tokens"] for c in self._calls]
        return {
            "mrm_record_id": self.mrm_record_id,
            "period": datetime.now(timezone.utc).strftime("%Y-%m"),
            "total_calls": len(self._calls),
            "output_token_mean": round(statistics.mean(output_tokens), 1),
            "output_token_stdev": round(statistics.stdev(output_tokens), 1) if len(output_tokens) > 1 else 0,
            "stop_reason_distribution": dict(
                zip(*[list(k) for k in zip(*[
                    (r, sum(1 for c in self._calls if c["stop_reason"] == r))
                    for r in set(c["stop_reason"] for c in self._calls)
                ])])
            ) if self._calls else {},
        }

# Usage
